Code.Terraform:
```hcl
resource "azuread_conditional_access_policy" "<example_resource_name>" {
  display_name = "<example_resource_name>"
  state        = "enabled"

  conditions {
    users {
      include_users = ["All"] # critical: include all users
    }
    applications {
      include_applications = ["d4ebce55-015a-49b5-a083-c84d1797ae8c"] # critical: target Microsoft Intune Enrollment app
    }
  }

  session_controls {
    sign_in_frequency {
      is_enabled = true      # critical: enable sign-in frequency control
      type       = "everyTime" # critical: require reauthentication every time
    }
  }
}
```
